// .NET 9: Lock type
public class ThreadSafeCounter
{
    private readonly Lock _lock = new();
    private int _count;

    public void Increment()
    {
        using (_lock.EnterScope()) // Scope là ref struct, tự động release
        {
            _count++;
        }
    }

    // Compiler nhận ra Lock type, gọi EnterScope()
    public int GetCount()
    {
        lock (_lock) { return _count; }
    }
}

// WRONG anti-patterns (cũ):
// lock(this) — bất kỳ caller nào cũng có thể lock object của bạn
// lock(typeof(MyClass)) — global lock cho toàn bộ app
// lock("constant") — string interning gây shared lock cross-class

// Kiểm tra deadlock với lock ordering
private static readonly Lock _lockA = new();
private static readonly Lock _lockB = new();

void SafeOp()
{
    using (_lockA.EnterScope()) // luôn A trước B
    using (_lockB.EnterScope())
    {
        // safe
    }
}
